import numpy as np

def relu(x):
    return np.maximum(0, x)

def leaky_relu(x, alpha=0.01):
    return np.where(x > 0, x, alpha * x)

# PReLU: alpha is a learnable vector (one per channel)
def prelu(x, alpha):
    # x shape (batch, channels, ...), alpha shape (channels,)
    return np.where(x > 0, x, alpha.reshape(-1, 1, 1) * x)

z = np.array([-2.0, -0.5, 0.0, 1.5, 3.0])
print("relu:", relu(z))
print("leaky_relu:", leaky_relu(z))
print("relu grad (x>0):", (z > 0).astype(float))
